import{_ as t,c as l,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.10：稳定性大升级","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.10.md","filePath":"changelog/v1.1.10.md","lastUpdated":1772014034000}'),d={name:"changelog/v1.1.10.md"};function o(n,e,h,s,c,p){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-1-10-稳定性大升级" tabindex="-1">v1.1.10：稳定性大升级 <a class="header-anchor" href="#v1-1-10-稳定性大升级" aria-label="Permalink to “v1.1.10：稳定性大升级”">​</a></h1><p><strong>发布日期</strong>：2026年1月9日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新主要是<strong>稳定性和体验优化</strong>，修复了分叉会话丢失、配置错误静默失败等问题，桌面版也更好用了。</p><hr><h2 id="重要修复-配置错误不再静默失败" tabindex="-1">重要修复：配置错误不再静默失败 <a class="header-anchor" href="#重要修复-配置错误不再静默失败" aria-label="Permalink to “重要修复：配置错误不再静默失败”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>如果你的配置文件（<code>settings.json</code>）有语法错误，OpenCode 会<strong>直接退出</strong>，不告诉你哪里出错了。很多用户以为是软件 bug，其实是配置写错了。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在 OpenCode 会<strong>明确报告配置错误</strong>，告诉你具体哪里出了问题，方便你快速修复。</p><hr><h2 id="重要修复-分叉会话不再丢失" tabindex="-1">重要修复：分叉会话不再丢失 <a class="header-anchor" href="#重要修复-分叉会话不再丢失" aria-label="Permalink to “重要修复：分叉会话不再丢失”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用「分叉会话」功能（从某条消息开始新对话）时，如果会话经过了压缩（compaction），分叉后的会话可能会<strong>丢失消息</strong>或显示异常。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了父子消息引用关系，分叉会话现在可以正常工作了。</p><p>👉 <strong>相关教程</strong>：<a href="/5-advanced/20-compaction.html">上下文压缩</a></p><hr><h2 id="改进-插件去重机制" tabindex="-1">改进：插件去重机制 <a class="header-anchor" href="#改进-插件去重机制" aria-label="Permalink to “改进：插件去重机制”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>如果你配置了多个同名插件（比如在全局和项目配置中都配置了同一个插件），OpenCode 现在会<strong>按优先级自动去重</strong>，避免重复加载。</p><p><strong>优先级规则</strong>：项目配置 &gt; 全局配置</p><hr><h2 id="桌面版改进" tabindex="-1">桌面版改进 <a class="header-anchor" href="#桌面版改进" aria-label="Permalink to “桌面版改进”">​</a></h2><p>这次桌面版有不少体验优化：</p><table tabindex="0"><thead><tr><th>改进</th><th>说明</th></tr></thead><tbody><tr><td>终端光标优化</td><td>光标改为竖线样式，失焦时停止闪烁</td></tr><tr><td>Zen 模式修复</td><td>新会话时模型选择器不再溢出</td></tr><tr><td>符号链接支持</td><td>完整支持 symlink，方便 monorepo 项目</td></tr><tr><td>终端/审查面板记忆</td><td>每个会话独立记住面板显示状态</td></tr></tbody></table><hr><h2 id="bedrock-用户-api-key-登录" tabindex="-1">Bedrock 用户：API Key 登录 <a class="header-anchor" href="#bedrock-用户-api-key-登录" aria-label="Permalink to “Bedrock 用户：API Key 登录”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>使用 Amazon Bedrock 的用户，现在可以在 <code>opencode auth login</code> 时直接输入 API Key 了。</p><p>之前只能通过环境变量或 AWS CLI 配置，现在多了一种更方便的方式。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>遇到过配置错误导致闪退</td><td>✅ 升级</td></tr><tr><td>用过分叉会话功能</td><td>✅ 升级</td></tr><tr><td>使用桌面版</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',36),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>禁用 server 模式，除非明确启用</li><li>配置错误时报告具体错误，而非静默退出（@ariane-emory）</li><li>升级 OpenTUI 到 v0.1.72</li><li>修复分叉会话在压缩后丢失父子消息引用的问题（@ryanwyler）</li><li>升级 OpenTUI 到 v0.1.71，修复能力检测和 Kitty 键盘支持</li><li>按优先级去重同名插件（@devxoul）</li><li>升级 Copilot 插件版本</li><li>修复模型对话框搜索问题，防止废弃模型出现在收藏/最近列表</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>Bedrock 登录时支持 API Key 输入（@Raviguntakala）</li></ul><h3 id="desktop-桌面版" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>移除内联 JavaScript</li><li>移除自定义 URL 参数</li><li>修复 Zen 模式下新会话模型选择器溢出（@0xajka）</li><li>完整实现符号链接支持，启用 PR CI（@jerome-benoit）</li><li>每个会话独立存储终端和审查面板可见性</li><li>终端光标改为竖线，失焦时停止闪烁（@dbpolito）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@RD201：文档添加 Scaleway 提供商</li><li>@dbpolito：桌面版终端光标优化</li><li>@devxoul：插件去重机制</li><li>@jerome-benoit：符号链接支持</li><li>@0xajka：Zen 模式修复</li><li>@ryanwyler：分叉会话修复</li><li>@Raviguntakala：Bedrock API Key 登录</li><li>@ariane-emory：配置错误报告</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const k=t(d,[["render",o]]);export{m as __pageData,k as default};
